What does this program print?

```cpp
#include <iostream>

struct Box {
    int* val;
    Box(int v) : val(new int(v)) {}
    Box(Box&& o) noexcept : val(o.val) { o.val = nullptr; }
    ~Box() { if (val) std::cout << "destroy " << *val << "\n"; }
};

int main() {
    Box a(7);
    Box b = std::move(a);
    return 0;
}
```

